cost_build_up.tier_1_formula:
// Tier 1: flat rate by subtype. Activity items: rate × weight or per skid/EA. Supply+install: base capacity rate.
const wt = skid_weight_tonnes ?? 1;
const lph = dosing_rate_lph ?? 100;
const conns = number_of_connections ?? 8;
const streams = number_of_streams ?? 1;
let cost = 0;
if (equipment_subtype === 'Skid fabrication') {
  cost = 1800 * wt;
} else if (equipment_subtype === 'Skid erection') {
  cost = 680 * wt;
} else if (equipment_subtype === 'Skid-mounted equipment installation') {
  cost = 4500;
} else if (equipment_subtype === 'Skid piping connection') {
  cost = 280 * conns;
} else if (equipment_subtype === 'Equipment skid alignment') {
  cost = 950;
} else if (equipment_subtype === 'Utility skid erection') {
  cost = 3800 + 680 * wt;
} else if (equipment_subtype === 'Chemical injection skid') {
  cost = lph <= 100 ? 28000 * Math.pow(lph/100, 0.60) : 28000 * Math.pow(lph/100, 0.45);
} else if (equipment_subtype === 'Metering skid') {
  cost = 35000 + Math.max(0, streams - 1) * 18000;
} else if (equipment_subtype === 'Chemical dosing skid') {
  cost = lph <= 50 ? 22000 * Math.pow(lph/50, 0.60) : 22000 * Math.pow(lph/50, 0.45);
}
quantity * cost

cost_build_up.tier_2_formula:
// Tier 2: Tier 1 × skid_type_factor × pressure_factor × service_factor
const wt = skid_weight_tonnes ?? 1;
const lph = dosing_rate_lph ?? 100;
const conns = number_of_connections ?? 8;
const streams = number_of_streams ?? 1;
const p = design_pressure_barg ?? 0;
// Pressure factor
const pf = p<=10 ? 1.0 : p<=40 ? 1.15 : p<=100 ? 1.45 : p<=250 ? 1.90 : 2.60;
// Skid type factor
const type_factors = {'Simple structural frame (pipe support / equipment support)':1.00,'Process skid (with valves, instruments, local panel)':1.80,'Packaged unit (complete self-contained process module)':2.80,'Pressure vessel skid (ASME VIII stamped vessels on skid)':3.50,'Cryogenic skid (low-temperature service, insulated)':3.20,'Modular building / E-house skid':2.50};
const tf = type_factors[skid_type] ?? 1.0;
// Service factor
const svc_factors = {'Water / utility (non-hazardous)':1.00,'Hydrocarbon — gas (flammable)':1.20,'Hydrocarbon — liquid (flammable)':1.15,'Chemical — corrosive (acid / alkali)':1.35,'Chemical — toxic (H2S / ammonia / chlorine)':1.55,'Cryogenic (LNG / LN2 / LOX)':1.70,'Steam / condensate':1.10,'Instrument air / inert gas':1.00};
const sf = svc_factors[skid_service] ?? 1.0;
let cost = 0;
if (equipment_subtype === 'Skid fabrication') {
  cost = 1800 * wt * tf * pf;
} else if (equipment_subtype === 'Skid erection') {
  cost = 680 * wt * pf;  // pressure factor applies (heavier flanged pipe to handle)
} else if (equipment_subtype === 'Skid-mounted equipment installation') {
  cost = 4500 * pf;
} else if (equipment_subtype === 'Skid piping connection') {
  cost = 280 * conns * pf;
} else if (equipment_subtype === 'Equipment skid alignment') {
  cost = 950;
} else if (equipment_subtype === 'Utility skid erection') {
  cost = (3800 + 680 * wt) * sf;
} else if (equipment_subtype === 'Chemical injection skid') {
  const base = lph <= 100 ? 28000 * Math.pow(lph/100, 0.60) : 28000 * Math.pow(lph/100, 0.45);
  cost = base * tf * pf * sf;
} else if (equipment_subtype === 'Metering skid') {
  const base = 35000 + Math.max(0, streams - 1) * 18000;
  cost = base * tf * pf * sf;
} else if (equipment_subtype === 'Chemical dosing skid') {
  const base = lph <= 50 ? 22000 * Math.pow(lph/50, 0.60) : 22000 * Math.pow(lph/50, 0.45);
  cost = base * tf * pf * sf;
}
quantity * cost

