cost_build_up.tier_1_formula:
// Tier 1: base unit rate × length (pipes) or × quantity (chambers). No depth/soil/material modifiers.
const pipe_subtypes = ['Storm Water Drain (RCC Pipe)', 'Storm Water Drain (Open Channel)', 'Storm Water Drain (Box Culvert)'];
const is_pipe = pipe_subtypes.includes(equipment_subtype);
if (is_pipe) {
  const d = pipe_diameter_mm ?? 450;
  const L = pipe_length_m ?? 1;
  let rate = 0;
  if (equipment_subtype === 'Storm Water Drain (RCC Pipe)')
    rate = 500 * Math.pow(d / 450, 0.80);
  else if (equipment_subtype === 'Storm Water Drain (Open Channel)')
    rate = 280 * Math.pow(d / 500, 0.70);
  else if (equipment_subtype === 'Storm Water Drain (Box Culvert)')
    rate = 650 * Math.pow(d / 600, 0.80);
  quantity * L * rate;
} else {
  const chamber_rates = {
    'Manhole (Circular - 1m dia)': 3200,
    'Manhole (Circular - 1.2m dia)': 4200,
    'Manhole (Rectangular - 1.5\u00d71m)': 5500,
    'Catch Pit (Street)': 1800,
    'Catch Basin (Roadside)': 2200,
    'Gully Trap (Chamber)': 900,
    'Soak Pit (Percolation)': 2800,
    'Inspection Chamber (Sewer)': 1400
  };
  quantity * (chamber_rates[equipment_subtype] ?? 2000);
}

cost_build_up.tier_2_formula:
// Tier 2: Tier 1 × depth_factor × soil_factor × material_factor. Manhole: base + depth adder.
const pipe_subtypes = ['Storm Water Drain (RCC Pipe)', 'Storm Water Drain (Open Channel)', 'Storm Water Drain (Box Culvert)'];
const is_pipe = pipe_subtypes.includes(equipment_subtype);
// Soil factor
const soil_factors = {'Normal (clay / silt / loose sand)':1.00,'Mixed (gravelly clay / dense sand / soft rock)':1.50,'Waterlogged / high water table (dewatering required)':2.00,'Hard rock (blasting / hydraulic breaker required)':3.50,'Made ground / demolition rubble':1.80,'Contaminated ground (special disposal required)':2.50};
const sf = soil_factors[soil_type] ?? 1.0;
// Material factor (applies to ~55% of pipe cost — supply component)
const mat_factors = {'RCC (Reinforced Concrete)':1.00,'HDPE (High Density Polyethylene)':0.85,'uPVC (Unplasticised PVC)':0.75,'GRP (Glass Reinforced Plastic)':1.35,'Vitrified Clay (VC)':1.10,'Ductile Iron (DI)':1.80,'Concrete (plain, non-reinforced)':0.88};
const mf_full = mat_factors[pipe_material] ?? 1.0;
const mf = 0.45 + 0.55 * mf_full;  // 45% labour unchanged + 55% material scaled
if (is_pipe) {
  const d = pipe_diameter_mm ?? 450;
  const L = pipe_length_m ?? 1;
  const depth = installation_depth_m ?? 1.5;
  // Depth factor: linear interpolation
  const df = 1.0 + Math.max(0, (depth - 1.5)) * 0.28;
  let rate = 0;
  if (equipment_subtype === 'Storm Water Drain (RCC Pipe)')
    rate = 500 * Math.pow(d / 450, 0.80);
  else if (equipment_subtype === 'Storm Water Drain (Open Channel)')
    rate = 280 * Math.pow(d / 500, 0.70);
  else if (equipment_subtype === 'Storm Water Drain (Box Culvert)')
    rate = 650 * Math.pow(d / 600, 0.80);
  quantity * L * rate * df * sf * mf;
} else {
  const base_rates   = {'Manhole (Circular - 1m dia)':3200,'Manhole (Circular - 1.2m dia)':4200,'Manhole (Rectangular - 1.5\u00d71m)':5500,'Catch Pit (Street)':1800,'Catch Basin (Roadside)':2200,'Gully Trap (Chamber)':900,'Soak Pit (Percolation)':2800,'Inspection Chamber (Sewer)':1400};
  const extra_per_m  = {'Manhole (Circular - 1m dia)':900,'Manhole (Circular - 1.2m dia)':1200,'Manhole (Rectangular - 1.5\u00d71m)':1500,'Catch Pit (Street)':600,'Catch Basin (Roadside)':700,'Gully Trap (Chamber)':350,'Soak Pit (Percolation)':1100,'Inspection Chamber (Sewer)':500};
  const ref_depths   = {'Manhole (Circular - 1m dia)':1.5,'Manhole (Circular - 1.2m dia)':1.5,'Manhole (Rectangular - 1.5\u00d71m)':1.5,'Catch Pit (Street)':1.2,'Catch Basin (Roadside)':1.2,'Gully Trap (Chamber)':1.0,'Soak Pit (Percolation)':2.0,'Inspection Chamber (Sewer)':1.2};
  const base = base_rates[equipment_subtype] ?? 2000;
  const epm  = extra_per_m[equipment_subtype] ?? 600;
  const ref_d = ref_depths[equipment_subtype] ?? 1.5;
  const depth = manhole_depth_m ?? ref_d;
  const depth_adder = Math.max(0, depth - ref_d) * epm;
  quantity * (base + depth_adder) * sf;
}

