cost_build_up.tier_1_formula:
// Tier 1: flat rate by subtype × power law scaling. Reference USA 2024.
// For transformers: cost = ref_cost × (kVA/ref_kVA)^exp
// For VFD: cost = 2200 × (motor_power/75)^0.72
// For MCC/Switchgear/UPS: flat rates
let cost = 0;
const kva = power ?? 1000;
const kw  = motor_power ?? 75;
if (equipment_subtype.includes('Distribution') && (equipment_subtype.includes('Oil') || equipment_subtype.includes('Cooled') || equipment_subtype.includes('1000 kVA') || equipment_subtype.includes('2000 kVA') || equipment_subtype.includes('Power Transformer (Distribution'))) {
  cost = 20000 * Math.pow(kva / 1000, 0.70);
} else if (equipment_subtype.includes('Dry Type') || equipment_subtype.includes('Cast Resin') || (equipment_subtype.includes('Distribution') && equipment_subtype.includes('Dry'))) {
  cost = 26000 * Math.pow(kva / 1000, 0.70);
} else if (equipment_subtype.includes('132')) {
  cost = 380000 * Math.pow(kva / 10000, 0.75);
} else if (equipment_subtype.includes('33') || equipment_subtype.includes('11/6.6') || equipment_subtype.includes('6.6kV') || equipment_subtype.includes('10 MVA')) {
  cost = 40000 * Math.pow(kva / 1000, 0.72);
} else if (equipment_subtype.includes('Earthing')) {
  cost = 18000 * Math.pow(kva / 200, 0.50);
} else if (equipment_subtype.includes('Auxiliary')) {
  cost = 12000 * Math.pow(kva / 500, 0.65);
} else if (equipment_subtype.includes('Unit Substation')) {
  cost = 25000 * Math.pow(kva / 500, 0.65);
} else if (equipment_subtype.includes('Switchgear')) {
  cost = 35000;
} else if (equipment_subtype.includes('MCC') || equipment_subtype.includes('Motor Control')) {
  cost = 8000 + (current ?? 630) * 0.635;
} else if (equipment_subtype.includes('VFD')) {
  cost = 2200 * Math.pow(kw / 75, 0.72);
} else if (equipment_subtype.includes('UPS')) {
  cost = 8500 * Math.pow(kva / 40, 0.73);
}
quantity * cost

